-- Migration: 3500 usuarios + 20000 compras + ajuste de ocupacao
SET NOCOUNT ON;

-- 0) Limpa estado parcial de tentativas anteriores
DELETE FROM dbo.purchases;
DELETE FROM dbo.users WHERE role='user' AND email != 'admin@fifa2026.com';

-- 1) 3500 usuarios em batches de 200

DECLARE @first_user_id INT = (SELECT MIN(id) FROM dbo.users WHERE role='user' AND email != 'admin@fifa2026.com');
PRINT 'Users inseridos. first_user_id detectado.';

-- 2) Staging table com 20000 compras + bulk JOIN com ticket_categories
CREATE TABLE #purchase_stage (
  match_id INT, category VARCHAR(50), user_offset INT, qty INT,
  status VARCHAR(20), payment_method VARCHAR(30), transaction_id VARCHAR(50), days_ago INT
);


-- 3) Bulk INSERT em purchases via JOIN com ticket_categories
SELECT
  @first_user_id + ps.user_offset,
  tc.id,
  ps.qty,
  tc.price,
  tc.price * ps.qty,
  ps.status,
  ps.payment_method,
  ps.transaction_id,
  DATEADD(day, -ps.days_ago, GETDATE()),
  DATEADD(day, -ps.days_ago, GETDATE())
FROM #purchase_stage ps
JOIN dbo.ticket_categories tc ON tc.match_id = ps.match_id AND tc.category = ps.category;
PRINT 'Purchases inseridas via bulk JOIN.';
DROP TABLE #purchase_stage;

-- 4) Ajuste de ocupacao agregada (target % vendido por jogo)
CREATE TABLE #occ_target (match_id INT, category VARCHAR(50), target_pct DECIMAL(5,3));

UPDATE tc
   SET available_quantity = CAST(tc.total_quantity * (1 - ot.target_pct) AS INT)
  FROM dbo.ticket_categories tc
  JOIN #occ_target ot ON ot.match_id = tc.match_id AND ot.category = tc.category;
DROP TABLE #occ_target;
PRINT 'Ocupacao agregada ajustada.';

-- 5) Decrementa available_quantity pelas 20k compras
CREATE TABLE #decrements (match_id INT, category VARCHAR(50), qty INT);

UPDATE tc
   SET available_quantity = CASE
       WHEN tc.available_quantity - d.qty < 0 THEN 0
       ELSE tc.available_quantity - d.qty
   END
  FROM dbo.ticket_categories tc
  JOIN #decrements d ON d.match_id = tc.match_id AND d.category = tc.category;
DROP TABLE #decrements;
PRINT 'Decrements aplicados.';

-- 6) Validacao final
SELECT COUNT(*) AS total_purchases FROM dbo.purchases;
SELECT COUNT(*) AS total_users FROM dbo.users WHERE role='user';
SELECT TOP 5 m.id, m.stage, m.group_name,
  SUM(tc.total_quantity) AS cap_total,
  SUM(tc.total_quantity - tc.available_quantity) AS vendidos,
  CAST(100.0 * SUM(tc.total_quantity - tc.available_quantity) / SUM(tc.total_quantity) AS DECIMAL(5,2)) AS pct
 FROM dbo.matches m JOIN dbo.ticket_categories tc ON tc.match_id = m.id
 WHERE m.stage IN ('final','semi_final','round_of_16') OR m.id IN (1, 13)
 GROUP BY m.id, m.stage, m.group_name ORDER BY m.id;